-- This testbench was generated by AI for quick result verification

library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;

entity tb_adder_subtractor is
end tb_adder_subtractor;

architecture behavior of tb_adder_subtractor is
    constant N : integer := 8;

    signal A      : std_logic_vector(N-1 downto 0) := (others => '0');
    signal B      : std_logic_vector(N-1 downto 0) := (others => '0');
    signal Sub    : std_logic := '0';
    signal Result : std_logic_vector(N-1 downto 0);

begin
    -- Підключення основного модуля
    uut: entity work.p_add_sub
        generic map (N => N)
        port map (
            A      => A,
            B      => B,
            Sub_b    => Sub,
            Res => Result
        );

    stim_proc: process
    begin
        report "--- SIMULATION START ---";
        wait for 10 ns;

        -- Test 1: Addition (10 + 5)
        A <= std_logic_vector(to_unsigned(10, N));
        B <= std_logic_vector(to_unsigned(5, N));
        Sub <= '0';
        wait for 10 ns;
        report "Test 1 (Add 10 + 5): Got = " & integer'image(to_integer(unsigned(Result)));
        assert unsigned(Result) = 15 report "Error in Test 1!" severity error;

        -- Test 2: Subtraction (10 - 5)
        Sub <= '1';
        wait for 10 ns;
        report "Test 2 (Sub 10 - 5): Got = " & integer'image(to_integer(unsigned(Result)));
        assert unsigned(Result) = 5 report "Error in Test 2!" severity error;

        -- Test 3: Addition (100 + 50)
        A <= std_logic_vector(to_unsigned(100, N));
        B <= std_logic_vector(to_unsigned(50, N));
        Sub <= '0';
        wait for 10 ns;
        report "Test 3 (Add 100 + 50): Got = " & integer'image(to_integer(unsigned(Result)));
        assert unsigned(Result) = 150 report "Error in Test 3!" severity error;

        -- Test 4: Overflow (255 + 1) for 8 bits
        A <= std_logic_vector(to_unsigned(255, N));
        B <= std_logic_vector(to_unsigned(1, N));
        Sub <= '0';
        wait for 10 ns;
        report "Test 4 (Overflow 255 + 1): Got = " & integer'image(to_integer(unsigned(Result)));
        assert unsigned(Result) = 0 report "Error in Test 4!" severity error;

        report "--- SIMULATION SUCCESSFULLY COMPLETED ---";
        wait; -- Зупиняємо процес
    end process;

end behavior;